{"code":"import json
import re

# Load citations
with open(locals()['var_function-call-9700206069512387348'], 'r') as f:
    citations_data = json.load(f)

citation_map = {}
for entry in citations_data:
    try:
        count = int(entry['citation_count'])
        citation_map[entry['title']] = count
    except ValueError:
        continue

# Load papers
with open(locals()['var_function-call-15345152852245153349'], 'r') as f:
    papers_data = json.load(f)

total_citations = 0
chi_papers_count = 0
chi_titles = []

for paper in papers_data:
    filename = paper.get('filename', '')
    if not filename.endswith('.txt'):
        continue

    title = filename[:-4]

    if title in citation_map:
        text = paper.get('text', '')
        # Check for CHI in first 5000 chars
        # strict "CHI" word match, case sensitive
        if re.search(r'\bCHI\b', text[:5000]):
            total_citations += citation_map[title]
            chi_papers_count += 1
            if len(chi_titles) < 5:
                chi_titles.append(title)

result = {
    "total_citations": total_citations,
    "chi_papers_count": chi_papers_count,
    "sample_chi_titles": chi_titles
}

print("__RESULT__:")
print(json.dumps(result))
"}

